const now = new Date();
const parts = now.toLocaleString('sv-SE', { timeZone: 'Europe/Moscow', hour12: false }).split(' ');
const datePart = parts[0] || '';
const timePart = parts[1] || '00:00:00';
const hour = Number((timePart.split(':')[0] || '0'));
let slot;
if (hour < 12) {
  slot = {
    slot_key: 'morning',
    slot_label: 'Утро',
    slot_prompt: 'Сделай полезный инфо-пост: короткий, ясный, с быстрым выводом и без тяжёлой подачи.',
    slot_chars_min: 320,
    slot_chars_max: 520,
    slot_source_profile: 'morning'
  };
} else if (hour < 17) {
  slot = {
    slot_key: 'day',
    slot_label: 'День',
    slot_prompt: 'Сделай лёгкий дневной пост: короче обычного, без воды, с живой подачей и понятным контекстом.',
    slot_chars_min: 260,
    slot_chars_max: 420,
    slot_source_profile: 'day'
  };
} else {
  slot = {
    slot_key: 'evening',
    slot_label: 'Вечер',
    slot_prompt: 'Сделай основной вечерний пост: самый сильный по подаче, с аккуратным заголовком, блоками и объяснением, почему это важно.',
    slot_chars_min: 480,
    slot_chars_max: 780,
    slot_source_profile: 'evening'
  };
}
return [{ json: { run_date_msk: datePart, run_time_msk: timePart.slice(0,5), ...slot } }];

const input = $input.first()?.json || {};
