const sourceUrl = $node["RSS Read"].parameter.url || "";
const provider = sourceUrl.includes("rsshub.app/telegram/channel") ? "tg" : "rss";

function getAllImages(html) {
  if (!html) return [];
  return Array.from(html.matchAll(/<img[^>]+src=["']([^"']+)["']/gi)).map((m) => (m[1] || "").trim());
}

function scoreImage(url) {
  if (!url) return -999;
  const value = url.toLowerCase();
  let score = 0;
  if (value.startsWith('http://') || value.startsWith('https://')) score += 5;
  if (/(jpg|jpeg|png|webp)(\?|$)/.test(value)) score += 4;
  if (/(hero|cover|header|featured|article|media|photo|images|uploads|bleepstatic)/.test(value)) score += 6;
  if (/(logo|icon|favicon|avatar|sprite|badge|brand|thumb-default)/.test(value)) score -= 20;
  if (/\b(64|96|128)x(64|96|128)\b/.test(value)) score -= 10;
  return score;
}

function pickBestImage(candidates) {
  const unique = [...new Set(candidates.map((v) => (v || '').trim()).filter(Boolean))];
  unique.sort((a, b) => scoreImage(b) - scoreImage(a));
  return unique[0] || '';
}

return $input.all().map((item) => {
  const json = item.json || {};
  const title = (json.title || "").toString().trim();
  const summary = (json.contentSnippet || json.content || json.summary || "").toString().trim();
  const link = (json.link || json.guid || "").toString().trim();
  const publishedAt = json.pubDate || json.isoDate || json.published || json.updated || "";
  const content = (json.content || json.summary || "").toString();
  const candidates = [
    json.enclosure?.url,
    json.enclosure?.link,
    json.image?.url,
    json.image?.link,
    json['media:content']?.url,
    json['media:thumbnail']?.url,
    ...getAllImages(content),
  ];
  const imageUrl = pickBestImage(candidates);
  const topicKey = `${title} ${summary}`.toLowerCase().replace(/\s+/g, " ").trim();
  return {
    title,
    summary,
    link,
    published_at: publishedAt,
    source_url: link || sourceUrl,
    source_provider: provider,
    topic_key: topicKey,
    image_url: imageUrl,
    slot_key: json.slot_key || '',
    slot_label: json.slot_label || '',
    slot_prompt: json.slot_prompt || '',
    slot_chars_min: json.slot_chars_min || 320,
    slot_chars_max: json.slot_chars_max || 780,
    run_date_msk: json.run_date_msk || '',
    run_time_msk: json.run_time_msk || ''
  };
});

const keywords = [
  "vpn",
  "приватност",
  "privacy",
  "data leak",
  "утеч",
  "кибер",
  "security",
  "breach",
  "block",
  "blocking",
  "restriction",
  "ограничен",
  "censorship",
  "telegram",
  "messenger"
];
const banned = [
  "war",
  "missile",
  "bombing",
  "killed",
  "combat",
  "invasion"
];
const items = $input.all().map((i) => i.json);
const filtered = items.filter((item) => {
  const text = `${item.title} ${item.summary}`.toLowerCase();
  if (banned.some((w) => text.includes(w))) {
    return false;
  }
  return keywords.some((w) => text.includes(w));
});
return filtered.map((item) => ({ json: item }));

