const content = (($json.choices || [])[0]?.message?.content || "").toString().toLowerCase();
const aiRelevant = content.includes("yes");
return { ...$json, ai_relevant: aiRelevant };

const candidate = $items('Limit Top')[0]?.json;
if (!candidate) {
  return [{ json: { skip: true, reason: 'no_candidates', slot_label: $items('Build Slot Context')[0]?.json?.slot_label || '' } }];
}
const payload = $json.data || $json;
const rows = Array.isArray(payload?.rows) ? payload.rows : $input.all().map((i) => i.json);
const now = Date.now();
const weekMs = 7 * 24 * 60 * 60 * 1000;
const cooldownMs = 2 * 60 * 60 * 1000;
const recentPending = rows.some((row) => {
  const status = (row.status || '').toString().toLowerCase();
  if (!['pending', 'approved'].includes(status)) return false;
  const ts = Date.parse(row.review_requested_at || row.approved_at || row.posted_at || '');
  return ts && Math.abs(now - ts) <= cooldownMs;
});
if (recentPending) {
  return [{ json: { skip: true, reason: 'cooldown', slot_label: candidate.slot_label || '' } }];
}
const dup = rows.some((row) => {
  if (!row || !row.topic_key) return false;
  const sameUrl = row.source_url && candidate.source_url && row.source_url === candidate.source_url;
  const sameTopic = row.topic_key && candidate.topic_key && row.topic_key === candidate.topic_key;
  const postedAt = row.posted_at || row.approved_at || row.review_requested_at || row.source_published_at;
  const ts = postedAt ? Date.parse(postedAt) : 0;
  const recent = ts ? Math.abs(now - ts) <= weekMs : false;
  return (sameUrl || sameTopic) && recent;
});
if (dup) {
  return [{ json: { skip: true, reason: 'duplicate', slot_label: candidate.slot_label || '' } }];
}
return [{ json: { skip: false, candidate } }];

const reason = ($json.reason || '').toString();
const slot = ($json.slot_label || $items('Build Slot Context')[0]?.json?.slot_label || '').toString();
let text = '⚠️ Нет релевантных новостей, публикуем резервный пост';
if (reason === 'duplicate') text = '⚠️ Дубликат новости, публикуем резервный пост';
if (reason === 'cooldown') text = '⚠️ Сработал cooldown, публикуем резервный пост';
if (slot) text += ` · слот ${slot.toLowerCase()}`;
const raw = ($env.CONTROL_APPROVAL_CHAT_IDS || $env.CONTROL_APPROVAL_CHAT_ID || '').toString();
const ids = raw.split(',').map((v) => v.trim()).filter(Boolean);
return ids.map((id) => ({ json: { chat_id: id, text } }));

