let text = (($json.choices || [])[0]?.message?.content || '').toString().trim();
text = text.replace(/^```[a-z]*\s*/i, '').replace(/```$/i, '').trim();
text = text.replace(/\r/g, '').replace(/\n{3,}/g, '\n\n');
if (!text) {
  text = `<b>${$json.title || 'Новая новость'}</b>\n\n<b>Что случилось</b>\n• ${($json.summary || 'Появился новый заметный инфоповод.').trim()}\n\n<b>Почему это важно</b>\n• Доступ к сервисам и цифровым инструментам может меняться быстрее, чем кажется.`;
}
if (!/<b>/.test(text)) {
  text = `<b>${$json.title || 'Новая новость'}</b>\n\n<b>Что случилось</b>\n${text}`;
}
return {
  ...$json,
  post_text: text
};

const now = new Date();
const id = now.getTime().toString();
return {
  ...$json,
  id,
  status: "pending",
  review_requested_at: now.toISOString()
};

const payload = $json.data || $json;
const itemId = (payload.id || '').toString();
return [{ json: { ...payload, item_id: itemId } }];

const payload = $json.data || $json;
const slot = (payload.slot_label || '').toString();
const source = (payload.title || payload.source_title || '').toString();
const mode = (payload.source_provider || '').toString() === 'evergreen' ? 'Резервный' : 'Новость';
const text = `✅ Автопост опубликован\n\nID: ${payload.id}\nТип: ${mode}${slot ? `\nСлот: ${slot}` : ''}${source ? `\nИсточник: ${source}` : ''}`;
const raw = ($env.CONTROL_APPROVAL_CHAT_IDS || $env.CONTROL_APPROVAL_CHAT_ID || '').toString();
const ids = raw.split(',').map((v) => v.trim()).filter(Boolean);
return ids.map((id) => ({ json: { chat_id: id, text } }));
